// Use pdf_texts_extracted (actual PDF docs with requirements) instead of pdf_text (GAEB BoQ)
const tender = $('load-tender').first().json;
const pdfTexts = tender.pdf_texts_extracted;
let extractionText = '';
if (pdfTexts) {
  if (Array.isArray(pdfTexts)) {
    extractionText = pdfTexts.map((t, i) => '=== Dokument ' + (i+1) + ' ===\n' + (t || '')).join('\n\n').slice(0, 12000);
  } else if (typeof pdfTexts === 'object') {
    extractionText = Object.entries(pdfTexts).map(([k, v]) => '=== ' + k + ' ===\n' + (v || '')).join('\n\n').slice(0, 12000);
  } else {
    extractionText = String(pdfTexts).slice(0, 12000);
  }
}
if (!extractionText && tender.pdf_text) {
  // Fallback to GAEB BoQ text if no extracted PDFs available
  extractionText = tender.pdf_text.slice(0, 12000);
}
return [{ json: { ...tender, extraction_text: extractionText } }];

const content = $json.choices[0].message.content;
let requirements = [];
try {
  const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  // Handle both array (new format) and object with requirements key (legacy)
  requirements = Array.isArray(parsed) ? parsed : (parsed.requirements || []);
} catch (e) {
  console.error('Failed to parse requirements:', e);
}
return [{ json: { requirements } }];

const raw = $json.choices[0].message.content || '';
const requirements = $('parse-requirements').first().json.requirements || [];

let title = null;
let summaryText = raw.trim();

// Try to parse as JSON {title, summary}
try {
  const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  if (parsed.title) title = parsed.title.trim();
  if (parsed.summary) summaryText = parsed.summary.trim();
} catch {
  // Model returned plain text — use as summary, no title update
}

return [{ json: { requirements, summary: summaryText, ai_title: title } }];

const parsed = $json;
const loadedTender = $('load-tender').first().json;
const update = {
  id: loadedTender.id,
  requirements: parsed.requirements || [],
  summary: parsed.summary || '',
  processing_status: 'details_ready',
};
// Only overwrite title if AI returned a meaningful non-code string
if (parsed.ai_title && typeof parsed.ai_title === 'string' && parsed.ai_title.trim().length > 3) {
  update.title = parsed.ai_title.trim();
}
return [{ json: update }];
